import{c as o,Q as i,j as d,m as l}from"./chunks/framework.BkjtU8k0.js";const n=JSON.parse('{"title":"更新日志","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":1780675511000}'),c={name:"changelog.md"};function a(r,e,t,s,u,f){return i(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="更新日志" tabindex="-1">更新日志 <a class="header-anchor" href="#更新日志" aria-label="Permalink to &quot;更新日志&quot;">​</a></h1><p>这份日志记录的是当前仓库主线中，对外最值得说明的能力演进。</p><h2 id="当前主线" tabindex="-1">当前主线 <a class="header-anchor" href="#当前主线" aria-label="Permalink to &quot;当前主线&quot;">​</a></h2><h3 id="v1-0-19-页面尺寸感知打印与入口组件瘦身版本" tabindex="-1"><code>v1.0.19</code> 页面尺寸感知打印与入口组件瘦身版本 <a class="header-anchor" href="#v1-0-19-页面尺寸感知打印与入口组件瘦身版本" aria-label="Permalink to &quot;`v1.0.19` 页面尺寸感知打印与入口组件瘦身版本&quot;">​</a></h3><ul><li>Vue3 包 <code>@flyfish-group/file-viewer3@1.0.19</code>、Vue2 包 <code>@flyfish-group/file-viewer@1.0.19</code>、React 包 <code>@flyfish-group/file-viewer-react@1.0.19</code> 和纯 JS 包 <code>@flyfish-group/file-viewer-web@1.0.19</code> 统一推进到连续版本</li><li>PDF 打印会按真实页面 CSS 尺寸生成完整高保真页图，并通过 <code>@page size</code> 固定输出纸张大小，避免导航窗格、视口宽度或缩放状态导致页面被挤压、裁切或只打印当前页</li><li>DOCX / DOC 打印保留白色纸张和文档页尺寸，导出窗口只包含主体页面，避免把 Demo 外壳、工具栏、滚动容器或预览缩放带入打印结果</li><li>新增 <code>printStyle</code> 渲染适配器能力，PDF、DOCX、DOC 等有真实页面尺寸的格式可以按文件自身尺寸输出打印样式，后续格式可复用同一机制</li><li>将下载、打印、导出 HTML 的实现从 <code>FileViewer.vue</code> 抽离到 <code>useViewerExport</code> 和导出模板 helper，入口组件回归预览状态、生命周期和操作可用性的单一职责</li><li>补充打印页尺寸与导出模板单测，并同步刷新文档站、README、Demo 示例版本、公开成品包和 npm 版本说明到 <code>1.0.19</code></li></ul><h3 id="v1-0-18-公开-issue-修复与真实-pdf-示例版本" tabindex="-1"><code>v1.0.18</code> 公开 issue 修复与真实 PDF 示例版本 <a class="header-anchor" href="#v1-0-18-公开-issue-修复与真实-pdf-示例版本" aria-label="Permalink to &quot;`v1.0.18` 公开 issue 修复与真实 PDF 示例版本&quot;">​</a></h3><ul><li>Vue3 包 <code>@flyfish-group/file-viewer3@1.0.18</code>、Vue2 包 <code>@flyfish-group/file-viewer@1.0.18</code>、React 包 <code>@flyfish-group/file-viewer-react@1.0.18</code> 和纯 JS 包 <code>@flyfish-group/file-viewer-web@1.0.18</code> 统一推进到连续版本</li><li>修复 GitHub issue #13: PDF 旋转页与导航配置兼容性增强，新增 <code>options.pdf.navigation</code> 和 <code>options.pdf.defaultNavigationVisible</code>，继续保持页侧边栏 / 树形目录侧边栏切换</li><li>修复 GitHub issue #9 与 #8: Excel 自动文本色更可靠，支持 workbook drawing 图片渲染，并按渲染链路隐藏不可靠的打印 / 导出入口</li><li>修复 GitHub issue #4: <code>.doc</code> 表格布局和单元格可读性增强，老 Word 文档在白色纸张容器里更接近实际阅读效果</li><li>修复 GitHub issue #1: <code>.doc</code> 的 <code>msdoc-viewer</code> CFB 局部 sector 容错改为包管理器无关的 <code>scripts/patch-msdoc-viewer.mjs</code>，npm / pnpm / yarn 安装后都可在构建前自动应用</li><li>Demo PDF 替换为项目方提供的 13 页《PDF沉浸式翻译技术说明》，用于验证长文档阅读、缩放、页导航、树形目录、完整打印和 HTML 导出</li><li>文档站、README、集成说明、示例来源、公开成品包和 npm 版本说明同步刷新到 <code>1.0.18</code></li></ul><h3 id="v1-0-17-打印能力矩阵与完整页打印版本" tabindex="-1"><code>v1.0.17</code> 打印能力矩阵与完整页打印版本 <a class="header-anchor" href="#v1-0-17-打印能力矩阵与完整页打印版本" aria-label="Permalink to &quot;`v1.0.17` 打印能力矩阵与完整页打印版本&quot;">​</a></h3><ul><li>Vue3 包 <code>@flyfish-group/file-viewer3@1.0.17</code>、Vue2 包 <code>@flyfish-group/file-viewer@1.0.17</code>、React 包 <code>@flyfish-group/file-viewer-react@1.0.17</code> 和纯 JS 包 <code>@flyfish-group/file-viewer-web@1.0.17</code> 统一推进到连续版本</li><li>PDF 导航窗格继续完善“页面 / 目录”切换，目录模式支持树形层级、展开折叠和定位跳转，便于用户在长文档中快速预览</li><li>Word、DOC 和 PDF 预览统一增强打印 / HTML 导出，专属导出适配器会移除预览缩放、滚动容器和 Demo 全局布局样式，避免只打印一页或页面被截断</li><li>新增打印能力动态判断，表格、压缩包、邮件、EPUB、音视频、3D 等不适合直接打印的渲染链路会自动隐藏打印按钮，避免用户进入错误打印流程</li><li>优化 Demo 暗色模式和 Markdown 阅读面，Markdown / 代码跟随系统主题，PDF / Word / Excel 等原始版式内容保持独立显示；同时替换更丰富的 DOCX / PDF / Markdown 示例并同步压缩包样例</li><li>新增文档加载、卸载生命周期钩子，以及下载、打印、导出 HTML 的按钮前置校验钩子，iframe 适配器同步透出事件和操作能力变化</li><li>文档站、README、集成说明、分发说明和公开成品包说明同步刷新到 <code>1.0.17</code></li></ul><h3 id="v1-0-15-预览交互、打印与集成钩子增强版本" tabindex="-1"><code>v1.0.15</code> 预览交互、打印与集成钩子增强版本 <a class="header-anchor" href="#v1-0-15-预览交互、打印与集成钩子增强版本" aria-label="Permalink to &quot;`v1.0.15` 预览交互、打印与集成钩子增强版本&quot;">​</a></h3><ul><li>PDF 导航窗格新增“页面 / 目录”切换，目录模式会读取 PDF 大纲并以可展开树形结构跳转，页面模式继续保留页侧边栏</li><li>增强 Word 和通用文档打印导出，<code>.docx</code> / <code>.doc</code> 会使用专属导出适配器清理预览缩放、绝对定位和滚动容器，避免只打印一页或页面被截断</li><li>新增 <code>options.hooks</code> 生命周期钩子，覆盖文档开始加载、加载完成、开始卸载和卸载完成，并提供文件类型、文件名、来源、URL、大小、版本和耗时上下文</li><li>新增 <code>options.beforeOperation</code> 与 toolbar 级前置操作钩子，下载、打印、导出 HTML 前都可以返回 <code>false</code> 取消，便于接入权限校验、审计确认和业务二次弹窗</li><li>React / 纯 JS iframe 适配层新增 viewer 事件监听入口，基线预览器会通过 <code>postMessage</code> 向宿主同步生命周期和操作事件</li><li>文档、README 和四条 npm 包线版本说明同步刷新到 <code>1.0.15</code></li></ul><h3 id="v1-0-14-最新发布与文档站同步版本" tabindex="-1"><code>v1.0.14</code> 最新发布与文档站同步版本 <a class="header-anchor" href="#v1-0-14-最新发布与文档站同步版本" aria-label="Permalink to &quot;`v1.0.14` 最新发布与文档站同步版本&quot;">​</a></h3><ul><li>Vue3 包 <code>@flyfish-group/file-viewer3@1.0.14</code>、Vue2 包 <code>@flyfish-group/file-viewer@1.0.14</code>、React 包 <code>@flyfish-group/file-viewer-react@1.0.14</code> 和纯 JS 包 <code>@flyfish-group/file-viewer-web@1.0.14</code> 统一抬升到最新版本</li><li>文档站首页、快速开始、分发说明、支持格式页和 README 中的安装示例同步刷新到 <code>1.0.14</code></li><li>公开成品仓库、Demo 静态产物和文档站静态产物重新构建，方便直接下载和验收</li><li>继续保持 Vue3 / Vue2 / React / 纯 JS 的集成路径、按需异步加载、示例分组和 PDF / OFD / 压缩包 / 邮件 / CAD / 绘图 / 电子书预览链路一致</li></ul><h3 id="v1-0-12-完整格式、成品仓库与-npm-同步版本" tabindex="-1"><code>v1.0.12</code> 完整格式、成品仓库与 npm 同步版本 <a class="header-anchor" href="#v1-0-12-完整格式、成品仓库与-npm-同步版本" aria-label="Permalink to &quot;`v1.0.12` 完整格式、成品仓库与 npm 同步版本&quot;">​</a></h3><ul><li>Vue3 包 <code>@flyfish-group/file-viewer3@1.0.12</code>、Vue2 包 <code>@flyfish-group/file-viewer@1.0.12</code>、React 包 <code>@flyfish-group/file-viewer-react@1.0.12</code> 和纯 JS 包 <code>@flyfish-group/file-viewer-web@1.0.12</code> 统一对齐到 npm <code>latest</code></li><li>新增压缩包预览，基于 <code>libarchive.js</code> Worker 支持 ZIP、7z、RAR、TAR、GZIP、BZIP2、XZ、CAB、ISO、JAR、APK、CBZ/CBR 等入口，内部文件按需解压、IndexedDB 缓存并继续调用统一预览器</li><li>新增 EML / MSG 邮件预览，支持头信息、HTML/文本正文、附件下载和附件继续在线预览</li><li>增强 OLB / DRA 结构预览，基于 <code>cfb</code> 解析常见 EDA 复合文档容器，并提供结构树、元件/封装/Padstack 候选、属性、诊断、二进制退化和可读字符串索引</li><li>预览器新增 <code>options.watermark</code>、<code>options.toolbar</code> 和 <code>options.archive</code>，支持文字/图片水印、下载原文件、完整打印、导出渲染后 HTML、压缩包 worker 和体积限制配置</li><li>修复 PDF 打印和导出 HTML 的完整性，PDF 会通过专属导出适配器逐页生成全部页面，不再依赖当前滚动视口、当前页或已渲染 canvas，避免只打印当前页或内容被截断</li><li>DWG 入口从单纯提示转换为尽力展示: 误命名 DXF 会直接按 DXF 解析，真实 DWG 会尝试提取内嵌 PNG/JPEG/BMP 预览图，并说明无法完整解析几何的原因</li><li>新增 Three.js 3D 模型预览器，支持 <code>glb</code>、<code>gltf</code>、<code>obj</code>、<code>stl</code>、<code>ply</code>、<code>fbx</code>、<code>dae</code>、<code>3ds</code>、<code>3mf</code>、<code>amf</code>、<code>usd</code>、<code>usda</code>、<code>usdc</code>、<code>usdz</code>、<code>kmz</code>、<code>pcd</code>、<code>wrl</code>、<code>vrml</code>、<code>xyz</code>、<code>vtk</code>、<code>vtp</code>；<code>step</code>、<code>stp</code>、<code>iges</code>、<code>igs</code>、<code>ifc</code>、<code>3dm</code> 会给出转换原因和建议</li><li>Demo 新增 GLTF / OBJ / STL / PLY / STEP 3D 样例，以及 ZIP、TAR.GZ、EML、MSG、OLB、DRA 样例，支持格式矩阵更新到 135 个扩展名、19 条预览链路</li><li>文档站全局导航、首页、格式矩阵、分发说明、快速开始和 npm README 均刷新到 <code>1.0.12</code></li><li>公开成品仓库继续只保留混淆压缩构建产物、Demo 静态站、文档静态站、样例文件和 tarball，不提交源码目录</li><li>React / 纯 JS 文档继续推荐 <code>npm install</code> 零步骤安装，并补充 pnpm 10 拦截 <code>postinstall</code> 时的 <code>pnpm approve-builds</code> / <code>pnpm exec file-viewer-copy-assets</code> 处理方式</li></ul><h3 id="v1-0-9-媒体、绘图与电子书预览增强版本" tabindex="-1"><code>v1.0.9</code> 媒体、绘图与电子书预览增强版本 <a class="header-anchor" href="#v1-0-9-媒体、绘图与电子书预览增强版本" aria-label="Permalink to &quot;`v1.0.9` 媒体、绘图与电子书预览增强版本&quot;">​</a></h3><ul><li>Vue3 包 <code>@flyfish-group/file-viewer3@1.0.9</code> 和 Vue2 包 <code>@flyfish-group/file-viewer@1.0.9</code> 同步发布到 npm <code>latest</code></li><li>新增 React 包 <code>@flyfish-group/file-viewer-react@1.0.9</code> 和纯 JS 包 <code>@flyfish-group/file-viewer-web@1.0.9</code>，通过 iframe 复用 Vue3 基线 viewer 静态产物</li><li>新增适配层 Demo，覆盖 React 组件和纯 JS helper 两种入口，构建后可直接作为私有化静态站点部署</li><li>增强 PPTX 渲染，补齐组合图形坐标映射、旋转/翻转、主题背景、图片裁剪和 EMF 转 SVG 预览</li><li>新增 <code>.epub</code> 预览，使用 <code>epubjs</code> 按需解析 EPUB 包、目录和滚动阅读，并避开部分浏览器超宽分页 iframe 白板问题</li><li>新增 <code>.umd</code> 电子书预览，按 UMD 文件结构解析元数据、章节目录和 zlib 压缩正文</li><li>新增 <code>.mp3</code>、<code>.mpeg</code>、<code>.wav</code>、<code>.ogg</code>、<code>.oga</code>、<code>.opus</code>、<code>.m4a</code>、<code>.aac</code>、<code>.flac</code>、<code>.weba</code> 音频入口，使用浏览器原生播放器</li><li>新增 <code>.excalidraw</code> 预览，使用官方 <code>@excalidraw/excalidraw</code> 的 <code>exportToSvg</code> 能力按需生成只读 SVG</li><li>新增 <code>.drawio</code> / <code>.dio</code> 预览，使用官方 diagrams.net <code>GraphViewer</code> 处理 mxGraphModel / mxfile</li><li>补充 Demo 示例文件、格式矩阵、FAQ 和接入说明</li></ul><h3 id="v1-0-8-文档视觉与预览稳定性版本" tabindex="-1"><code>v1.0.8</code> 文档视觉与预览稳定性版本 <a class="header-anchor" href="#v1-0-8-文档视觉与预览稳定性版本" aria-label="Permalink to &quot;`v1.0.8` 文档视觉与预览稳定性版本&quot;">​</a></h3><ul><li>Vue3 包 <code>@flyfish-group/file-viewer3@1.0.8</code> 和 Vue2 包 <code>@flyfish-group/file-viewer@1.0.8</code> 同步发布到 npm <code>latest</code></li><li>修复 PDF worker 生命周期，快速切换 PDF / OFD / PDF 时不再触发 worker 销毁告警</li><li>稳定 OFD 渲染状态，避免反复闪动“正在解析 OFD”</li><li>刷新文档站截图、主题配色和 iframe 示例页视觉</li></ul><h3 id="v1-0-7-pdf-自适应修复版本" tabindex="-1"><code>v1.0.7</code> PDF 自适应修复版本 <a class="header-anchor" href="#v1-0-7-pdf-自适应修复版本" aria-label="Permalink to &quot;`v1.0.7` PDF 自适应修复版本&quot;">​</a></h3><ul><li>Vue3 包 <code>@flyfish-group/file-viewer3@1.0.7</code> 和 Vue2 包 <code>@flyfish-group/file-viewer@1.0.7</code> 同步发布到 npm <code>latest</code></li><li>修复 PDF.js 5 下 canvas 布局尺寸被 DPR backing store 干扰的问题，避免 PDF 页面被裁切或显示不完整</li><li>修复 PDF 默认宽度适配计算，导航窗格开启时也能按当前视口宽度给出可读缩放比例</li><li>同步刷新线上 Demo、文档说明和公开成品仓库产物</li></ul><h3 id="v1-0-6-成品分发版本" tabindex="-1"><code>v1.0.6</code> 成品分发版本 <a class="header-anchor" href="#v1-0-6-成品分发版本" aria-label="Permalink to &quot;`v1.0.6` 成品分发版本&quot;">​</a></h3><ul><li>Vue3 包 <code>@flyfish-group/file-viewer3@1.0.6</code> 和 Vue2 包 <code>@flyfish-group/file-viewer@1.0.6</code> 均已发布到 npm <code>latest</code></li><li>新增 PDF 缩放工具栏、页码状态和可显隐页面导航窗格</li><li>补齐 OFD、CAD、代码高亮与完整示例文件盒子</li><li>示例文件选择器支持分组折叠，默认展开第一个分组，并保持同一时间只展开一个分组</li><li>增加 <code>pnpm obfuscate</code> 与 <code>pnpm release:pack</code>，库产物支持压缩混淆后分发</li><li>README、文档站和公开成品仓库说明同步补充 npm、GitHub、源码自助开通、授权与贡献说明</li><li>npm tarball 只包含 <code>README.md</code>、<code>LICENSE</code> 和混淆压缩后的 <code>dist/</code></li></ul><h3 id="文档站与交付说明完善" tabindex="-1">文档站与交付说明完善 <a class="header-anchor" href="#文档站与交付说明完善" aria-label="Permalink to &quot;文档站与交付说明完善&quot;">​</a></h3><ul><li>重写 README 与 VitePress 文档结构</li><li>增加 Demo 说明、本地开发与打包说明</li><li>补充截图、接入建议与发布前检查清单</li></ul><h3 id="doc-渲染能力升级" tabindex="-1"><code>.doc</code> 渲染能力升级 <a class="header-anchor" href="#doc-渲染能力升级" aria-label="Permalink to &quot;`.doc` 渲染能力升级&quot;">​</a></h3><ul><li>使用 <code>msdoc-viewer</code> 替换旧的 <code>.doc</code> 解析方案</li><li>将 <code>.doc</code> 内容渲染在 Word 风格页面容器中</li><li>增加灰色工作台、白色纸张与页面居中展示效果</li></ul><h3 id="示例与工程体验" tabindex="-1">示例与工程体验 <a class="header-anchor" href="#示例与工程体验" aria-label="Permalink to &quot;示例与工程体验&quot;">​</a></h3><ul><li>提供更清晰的本地 Demo 入口说明</li><li>支持将预览器独立部署并通过 iframe 集成</li><li>本地构建、文档站构建与 npm 打包链路持续收敛</li></ul><h2 id="历史版本" tabindex="-1">历史版本 <a class="header-anchor" href="#历史版本" aria-label="Permalink to &quot;历史版本&quot;">​</a></h2><h3 id="v1-0-3" tabindex="-1"><code>v1.0.3</code> <a class="header-anchor" href="#v1-0-3" aria-label="Permalink to &quot;`v1.0.3`&quot;">​</a></h3><ul><li>修复与优化 PDF 字体、缩放和 Excel 样式相关问题</li></ul><h3 id="更早版本" tabindex="-1">更早版本 <a class="header-anchor" href="#更早版本" aria-label="Permalink to &quot;更早版本&quot;">​</a></h3><ul><li>优化 PPTX 加载性能</li><li>补强 Word 与 Excel 的基础预览能力</li><li>持续完善 TypeScript 与 Vue 3 版本实现</li></ul><div class="doc-note"> npm 包版本请以 `package.json` 和实际发布记录为准；本页更偏向说明“这个仓库当前已经演进到了哪里”。 </div>',35)])])}const p=o(c,[["render",a]]);export{n as __pageData,p as default};
